 import PostCard from "../components/PostCard";
import { useNavigate } from "react-router-dom";

function Home() {
  const navigate = useNavigate();

  const posts = [
    {
      id: 1,
      title: "MERN Stack Guide",
      content: "Learn MERN stack from scratch and build full stack applications.",
      author: "Kavya",
      likes: 12,
      comments: 5,
      image: "https://images.unsplash.com/photo-1506744038136-46273834b3fb"
    },
    {
      id: 2,
      title: "React Tutorial",
      content: "A complete guide to learn React step by step.",
      author: "Admin",
      likes: 8,
      comments: 3,
      image: "https://images.unsplash.com/photo-1633356122544-f134324a6cee"
    },
    {
      id: 3,
      title: "JavaScript Basics",
      content: "Understand JavaScript fundamentals.",
      author: "Suresh",
      likes: 6,
      comments: 2,
      image: "https://images.unsplash.com/photo-1515879218367-8466d910aaa4"
    }
  ];

  return (
    <>
      <section className="hero">
        <div className="hero-left">
          <h3>Welcome to</h3>

          <h1>
            Our <span>Blog Platform</span>
          </h1>

          <p>
            Discover amazing stories, ideas and insights from writers around the world.
          </p>

          <button
            className="explore-btn"
            onClick={() => navigate("/dashboard")}
          >
            Explore Blogs →
          </button>
        </div>

        <div className="hero-right">
          <img
            src="https://illustrations.popsy.co/purple/woman-working-from-home.svg"
            alt="Blog Illustration"
          />
        </div>
      </section>

      <h2 className="section-title">
        Latest Blog Posts
      </h2>

      <div className="posts-grid">
        {posts.map((post) => (
          <PostCard
            key={post.id}
            post={post}
          />
        ))}
      </div>
    </>
  );
}

export default Home;
